This function returns the average (or mean) of the elements of a vector.
[[cpp11::register]] double mean_cpp_(doubles x) {
  int n = x.size();
  double y = 0;

  for(int i = 0; i &lt; n; ++i) {
    // y += x[i] / n;
    // replace N divisions with 1 division at the end
