Variance (var())
This function returns the variance of the elements of a vector.
[[cpp11::register]] double var2_cpp_(doubles x, bool na_rm = false) {
  int n = x.size();

  if (n &lt; 2) {
    return NA_REAL;
  }

  int m = 0;
  for (int i = 0; i &lt; n; ++i) {
    if (na_rm && ISNAN(x[i])) {
      continue;
    } else {
      ++m;
    }
  }

  if (m &lt; 2) {
    return NA_REAL;
  }

  double ex = 0;
  for (int i = 0; i &lt; n; ++i) {
    if (na_rm && ISNAN(x[i])) {
      continue;
    } else {
      ex += x[i];
    }
  }
  ex /= m;

  double out = 0;
  for (int i = 0; i &lt; n; ++i) {
    if (na_rm && ISNAN(x[i])) {
      continue;
    } else {
      out += pow(x[i] - ex, 2);
    }
  }

  return out / (m - 1);
}
